import { MissingBullSharedConfigurationError } from '../errors/missing-shared-bull-config.error';

export interface IConditionalDepHolder<T = any> {
  getDependencyRef(caller: string): T;
}

export function createConditionalDepHolder<T = any>(
  depToken: string,
  optionalDep: string,
  errorFactory = (caller: string) =>
    new MissingBullSharedConfigurationError(depToken, caller),
): Type<IConditionalDepHolder> {
  class ConditionalDepHolder {
    constructor(@Optional() @Inject(depToken) public _dependencyRef: T) {}

    getDependencyRef(caller: string): T {
      if (depToken !== optionalDep && !this._dependencyRef) {
        throw errorFactory(caller);
      }
      return this._dependencyRef;
    }
  }
  return mixin(ConditionalDepHolder);
}

export function Prop(options?: PropOptions): PropertyDecorator {
  return (target: object, propertyKey: string | symbol) => {
    options = (options || {}) as mongoose.SchemaTypeOptions<unknown>;

    const isRawDefinition = options[RAW_OBJECT_DEFINITION];
    if (!options.type && !Array.isArray(options) && !isRawDefinition) {
      const type = Reflect.getMetadata(TYPE_METADATA_KEY, target, propertyKey);

      if (type === Array) {
        options.type = [];
      } else if (type && type !== Object) {
        options.type = type;
      } else {
        throw new CannotDetermineTypeError(
          target.constructor?.name,
          propertyKey as string,
        );
      }
    }

    TypeMetadataStorage.addPropertyMetadata({
      target: target.constructor,
      propertyKey: propertyKey as string,
      options: options as PropOptions,
    });
  };
}

export class UserAccessAuthCheck extends AuthCheckContract<ScopedData, any> {
  constructor() {
    super();
  }

  public async isAuthorized(params: AuthorizationCheckParams<ScopedData, any>): Promise<boolean> {
    if (!params || !params.targetResource || !params.targetResource.userId) throw new AuthorizationCheckError(params, 'AuthorizationCheckParams - userId can not be null');

    if (!params.accessPermissions) return false;

    // if self, then true
    if (params.accessPermissions.userId && params.accessPermissions.userId.toString() === params.targetResource.userId.toString()) return true;

    // if system admin, then true
    if (isStaffAdmin(params.accessPermissions)) return true;

    // if doesn't have orgId, can't verify access through org scope.  Return false
    if (!params.targetResource.orgId) return false;

    // if org admin, then true
    return hasOrganizationRole(params.accessPermissions, params.targetResource.orgId, [OrganizationRoles.facilitator, OrganizationRoles.admin]);
  }
}

